var e=[{id:`L2_1`,type:`dialog`,speaker:`CHINATSU_NANA_NULL_NULL`,text:{KOREA:`헉…… 허억……`,JPN:`はぁ……はぁ……`,ENG:`*Pant*`,TWN:`咳……咳咳……`},stage:{bg:`REEDS_FIELD`,slots:{L:null,C:{char_id:`CHINATSU_NANA_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L4_1`,type:`dialog`,speaker:`OROCHI_JAPAN_NULL_NULL`,text:{KOREA:`후후, 이렇게나 간단한 것을 굳이 어렵게 갈 필요는 없지.`,JPN:`ふふ、こんな簡単なことをあえて難しくやる必要はない。`,ENG:`Yes, it’s so simple.`,TWN:`呵呵，事情明明很簡單，有必要搞成這樣嗎？`},stage:{bg:`REEDS_FIELD`,slots:{L:null,C:{char_id:`CHINATSU_NANA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L5_1`,type:`dialog`,speaker:`OROCHI_JAPAN_NULL_NULL`,text:{KOREA:`어떠냐? 인간이라면 탐낼 법도 한 힘이지?`,JPN:`どうだ？　人間なら欲しがる力だろう？`,ENG:`What do you say? This certainly is a power that any human would covet, don’t you agree?`,TWN:`如何？這是人類很想要的力量吧？`},stage:{bg:`REEDS_FIELD`,slots:{L:null,C:{char_id:`OROCHI_JAPAN_NULL_NULL`,face:`UNIT_PRIDE`},R:null}}},{id:`L8_1`,type:`dialog`,speaker:`OROCHI_JAPAN_NULL_NULL`,text:{KOREA:`음?`,JPN:`うん？`,ENG:`Huh?`,TWN:`嗯？`},stage:{bg:`REEDS_FIELD`,slots:{L:null,C:{char_id:`OROCHI_JAPAN_NULL_NULL`,face:`UNIT_SERIOUS2`},R:null}}},{id:`L10_1`,type:`dialog`,speaker:`CHIFUYU_NANA_NULL_NULL`,text:{KOREA:`당주님께는…… 갈 수 없다.`,JPN:`当主には……近づかせない。`,ENG:`I will not let you hurt... my Lady...`,TWN:`不可以……去找堂主。`},stage:{bg:`REEDS_FIELD`,slots:{L:null,C:{char_id:`OROCHI_JAPAN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`CHINATSU_NANA_NULL_NULL`,text:{KOREA:`치후유!`,JPN:`千冬！`,ENG:`Chifuyu!`,TWN:`千冬！`},stage:{bg:`REEDS_FIELD`,slots:{L:null,C:{char_id:`CHINATSU_NANA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`OROCHI_JAPAN_NULL_NULL`,text:{KOREA:`주제를 모르고 내 발목을 잡다니.`,JPN:`身の程知らずが我の足を掴むとは。`,ENG:`How dare you touch me.`,TWN:`也不掂掂自己幾兩重，竟敢攔我！`},stage:{bg:`REEDS_FIELD`,slots:{L:null,C:{char_id:`OROCHI_JAPAN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`OROCHI_JAPAN_NULL_NULL`,text:{KOREA:`얌전히 죽어가면서 기다리고 있거라. 곧 그 몸에서 예쁜 구슬을 뽑아줄 테니.`,JPN:`大人しく死にながら待っていなさい。
すぐその体から綺麗な玉を抜き取ってやる。`,ENG:`Stay here and wait for me. I’ll be back to make a pretty orb out of you.`,TWN:`乖乖的去死後等我，我很快就會從你身上取出漂亮的珠子。`},stage:{bg:`REEDS_FIELD`,slots:{L:null,C:{char_id:`OROCHI_JAPAN_NULL_NULL`,face:`UNIT_PRIDE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`CHINATSU_NANA_NULL_NULL`,text:{KOREA:`안 돼……`,JPN:`いけない……`,ENG:`No...`,TWN:`不可以……`},stage:{bg:`REEDS_FIELD`,slots:{L:null,C:{char_id:`CHINATSU_NANA_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`CHINATSU_NANA_NULL_NULL`,text:{KOREA:`이젠 정말 버티기가……`,JPN:`これ以上は持ちこたえることが……`,ENG:`I can’t stand it anymore...`,TWN:`我真的撐不……`},stage:{bg:`REEDS_FIELD`,slots:{L:null,C:{char_id:`CHINATSU_NANA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L22_1`,type:`dialog`,speaker:`CHINATSU_NANA_NULL_NULL`,text:{KOREA:`뭐지? 가면에서…… 빛이?`,JPN:`なに？　お面から……光が？`,ENG:`What’s this? The mask... It’s shining!`,TWN:`什麼？面具裡有……光？`},stage:{bg:`REEDS_FIELD`,slots:{L:null,C:{char_id:`CHINATSU_NANA_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L25_1`,type:`dialog`,speaker:null,text:{KOREA:`하아…… 하아……`,JPN:`はあ……はあ……`,ENG:`*Pant*`,TWN:`呼呼……呼呼……`},stage:{bg:`FOREST_NORMAL_02`,slots:{L:null,C:null,R:null}}},{id:`L26_1`,type:`dialog`,speaker:null,text:{KOREA:`찾아라! 멀리 가지 못했다!`,JPN:`探せ！　遠くまでは逃げていないはずだ！`,ENG:`Find her! She won’t be far!`,TWN:`快找！應該沒跑遠！`},stage:{bg:`FOREST_NORMAL_02`,slots:{L:null,C:null,R:null}}},{id:`L27_1`,type:`dialog`,speaker:`KANADE_JAPAN_NULL_MASKED`,text:{KOREA:`당주님은, 여기 숨어 계십시오.`,JPN:`ご当主様はここに隠れていてください。`,ENG:`Stay here, Lady.`,TWN:`堂主，您就躲在這裡。`},stage:{bg:`FOREST_NORMAL_02`,slots:{L:null,C:{char_id:`KANADE_JAPAN_NULL_MASKED`,face:`UNIT_SERIOUS2`},R:null}}},{id:`L28_1`,type:`dialog`,speaker:`KANADE_JAPAN_NULL_MASKED`,text:{KOREA:`제가 배반자들을 처리하겠습니다.`,JPN:`私が裏切り者を始末します。`,ENG:`I’ll go take care of the betrayers.`,TWN:`我去解決叛徒。`},stage:{bg:`FOREST_NORMAL_02`,slots:{L:null,C:{char_id:`KANADE_JAPAN_NULL_MASKED`,face:`UNIT_IDLE`},R:null}}},{id:`L30_1`,type:`dialog`,speaker:null,text:{KOREA:`카나데…… 미안하다.`,JPN:`かなで……すまない。`,ENG:`Kanade... I’m sorry.`,TWN:`速水奏……對不起。`},stage:{bg:`FOREST_NORMAL_02`,slots:{L:null,C:{char_id:`KANADE_JAPAN_NULL_MASKED`,face:`UNIT_IDLE`},R:null}}}];export{e as default};